var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"안녕?","JPN":"ハロー。","ENG":"Hi!","TWN":"嗨？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"오랜만이야, 즐거운 코핀 친구들~!","JPN":"久しぶりね。コフィンの愉快な仲間たち～！","ENG":"Long time no see, Coffineers!","TWN":"好久不見，科芬的朋友們！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하. 실비아 양도 건강해 보이셔서 다행입니다.","JPN":"ハハ、シルビアさんもお元気そうでなによりです。","ENG":"Haha. I’m glad to see you’ve been doing well too.","TWN":"哈哈！希爾維亞小姐看起來氣色很好呢！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그래 보여? 통신 화질이 별로 안 좋은가 보네.","JPN":"そう見える？　画質があまり良くないみたいね。","ENG":"Does it look like I’m doing well? The video feed must be faulty.","TWN":"是嗎？看來通信畫質不是很好啊。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"지금 눈 밑에 다크 서클이 이렇게 늘어나 있는데 말이지.","JPN":"目の下にクマがこーんなに伸びてるのにさ。","ENG":"I've got bags under my eyes so big I could probably fit my groceries in there.","TWN":"我最近黑眼圈很重呢。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......의외야.","JPN":"……意外。","ENG":"I must say, I’m a bit surprised.","TWN":"……真是意外。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"지난번에는 신뢰가 어쩌고 하면서 뭐 다시는 연락 안 할 것처럼 굴더니......","JPN":"この前は信頼がどうのこうの言って、二度と連絡しない気満々に見えたのに……","ENG":"You went on about trust or whatever last time, as if you’d never reach out to us again...","TWN":"上次有人才說雙方的信任如何如何，然後說不會再跟我們聯絡了……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그랬던가? 하하, 잘 기억이 안 나네?","JPN":"そうだったかしら？　ハハ、あまり覚えてないかも。","ENG":"Did I? Haha... I’m not sure I remember...","TWN":"是嗎？記不太清楚了呢。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"뭐, 지금 같은 비상 시국에 사소한 오해 정도는 얼마든지 덮어 둘 수 있는 거니까.","JPN":"まあ、非常事態なんだし、ちょっとした誤解ぐらいはしょうがないよね。","ENG":"Anyway, I’m sure I can put some trivial misunderstanding like that aside in an emergency like this.","TWN":"現在事態緊急，那些微不足道的誤會大家就別計較了吧。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......뻔뻔해.","JPN":"……ふてぶてしいな。","ENG":"How shameless...","TWN":"……臉皮真厚。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"유감이야. 그 아줌마라면 충분히 이해해 줬을 텐데.","JPN":"残念ね～。あのオバサンなら十分理解してくれるでしょうに。","ENG":"It’s too bad, really. I’m sure the old lady would've understood.","TWN":"真遺憾，要是那位大嬸在的話肯定可以理解的。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그러고 보니 그 아줌마는 어디에 있어? 여기엔 안 보이네?","JPN":"そういえば、あのオバサンはどこ？　見当たらないわね。","ENG":"Speaking of which, where is that lady? I don’t see her over there.","TWN":"這麼一說，那位大嬸在哪裡啊？沒來嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"아쉽지만 이수연 부사장은 본사에서 대기 중이다.","JPN":"残念だが、カナミ副社長は本社で待機している。","ENG":"Regrettably, Vice President Lee is standing by at HQ.","TWN":"很遺憾，副總李秀妍今天在總公司。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"나중에 안부 전하도록 하지.","JPN":"後でよろしく伝えておくよ。","ENG":"I’ll tell her you said hi.","TWN":"我之後會幫妳和她問好的。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그보다 이쪽에서 요청한 정보는 어떻게 됐지? 찾았나?","JPN":"それより、こちらから要請した情報はどうなった？　見つけたか？","ENG":"More importantly, what's the status on the intel we requested? Did you find anything?","TWN":"不說這些了，我們要求的資訊怎麼樣了？找到了嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"음...... 그거 말이지......","JPN":"うーん……あれね……","ENG":"Well... About that...","TWN":"呃……那個嘛……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"뭐, 찾긴 했어.","JPN":"まぁ、見つかってはいるんだけど。","ENG":"We did find something.","TWN":"找是找到了，但是……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"국무부 쪽의 연줄을 총동원해서 전 세계 사건 기록을 탈탈 털었으니까.","JPN":"国務省のコネというコネを全部使って、世界中の事件記録を漁ったからね。","ENG":"We called in every favor stacked up with the State Department to search through all the cases across the world.","TWN":"國務部那邊動用了關係，把全世界範圍內的事件記錄都拿走了。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그런데 정말 이 정보가 이번 사건을 해결하는 데 도움이 되는 거 맞아?","JPN":"ところで、本当にこの情報が今回の事件を解決するのに役立つの？","ENG":"But are you sure this intel will help you solve this case?","TWN":"這個資訊真的有助於解決這次事件嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};